  OPTIONAL MATCH (org)-[:IN_INDUSTRY]->(cat:IndustryCategory)
  RETURN collect(DISTINCT cat.name) AS industries
}
CALL (org) {
  OPTIONAL MATCH (a:Article)-[:MENTIONS]->(org)
  RETURN count(a) AS articleCount
}
CALL (org) {
  OPTIONAL MATCH (a:Article)-[:MENTIONS]->(org)
  WITH a LIMIT 3
  RETURN collect(a.title) AS topHeadlines
}
CALL (org) {
  OPTIONAL MATCH (org)-[:HAS_SUBSIDIARY]->(sub:Organization)
  RETURN count(sub) AS subsidiaryCount
}
RETURN org.name        AS company,
       score,
       industries,
       topHeadlines,
       articleCount,
       subsidiaryCount
ORDER BY score DESC
